INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"zoom-in-zoom-out-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".zoom-in-out-box {\n  margin: 24px;\n  width: 50px;\n  height: 50px;\n  background: #f50057;\n  animation: zoom-in-zoom-out 1s ease infinite;\n}\n\n@keyframes zoom-in-zoom-out {\n  0% {\n    transform: scale(1, 1);\n  }\n  50% {\n    transform: scale(1.5, 1.5);\n  }\n  100% {\n    transform: scale(1, 1);\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Zoom in zoom out animation\r\n    </h1>\r\n    <div class=\"zoom-in-out-box\"></div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/zoom-in-zoom-out-animation"}'), ('"custom-checkbox"', '"Prsnt"', '"vanilla"', '{"demo.css": ".checkbox-symbol {\n  position: absolute;\n  width: 0;\n  height: 0;\n  pointer-events: none;\n  user-select: none;\n}\n\n.checkbox-container {\n  box-sizing: border-box;\n  background: #ffffff;\n  color: #222;\n  height: 64px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-flow: row wrap;\n}\n\n.checkbox-container * {\n  box-sizing: border-box;\n}\n\n.checkbox-input {\n  position: absolute;\n  visibility: hidden;\n}\n\n.checkbox {\n  user-select: none;\n  cursor: pointer;\n  padding: 6px 8px;\n  border-radius: 6px;\n  overflow: hidden;\n  transition: all 0.3s ease;\n  display: flex;\n}\n\n.checkbox:not(:last-child) {\n  margin-right: 6px;\n}\n\n.checkbox:hover {\n  background: rgba(0, 119, 255, 0.06);\n}\n\n.checkbox span {\n  vertical-align: middle;\n  transform: translate3d(0, 0, 0);\n}\n\n.checkbox span:first-child {\n  position: relative;\n  flex: 0 0 18px;\n  width: 18px;\n  height: 18px;\n  border-radius: 4px;\n  transform: scale(1);\n  border: 1px solid #cccfdb;\n  transition: all 0.3s ease;\n}\n\n.checkbox span:first-child svg {\n  position: absolute;\n  top: 3px;\n  left: 2px;\n  fill: none;\n  stroke: #fff;\n  stroke-dasharray: 16px;\n  stroke-dashoffset: 16px;\n  transition: all 0.3s ease;\n  transform: translate3d(0, 0, 0);\n}\n\n.checkbox span:last-child {\n  padding-left: 8px;\n  line-height: 18px;\n}\n\n.checkbox:hover span:first-child {\n  border-color: #0077ff;\n}\n\n.checkbox-input:checked + .checkbox span:first-child {\n  background: #0077ff;\n  border-color: #0077ff;\n  animation: zoom-in-out 0.3s ease;\n}\n\n.checkbox-input:checked + .checkbox span:first-child svg {\n  stroke-dashoffset: 0;\n}\n\n@keyframes zoom-in-out {\n  50% {\n    transform: scale(0.9);\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Custom checkbox\r\n    </h1>\r\n    <svg class=\"checkbox-symbol\">\r\n      <symbol id=\"check\" viewbox=\"0 0 12 10\">\r\n        <polyline\r\n          points=\"1.5 6 4.5 9 10.5 1\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n          stroke-width=\"2\"\r\n        ></polyline>\r\n      </symbol>\r\n    </svg>\r\n\r\n    <div class=\"checkbox-container\">\r\n      <input class=\"checkbox-input\" id=\"apples\" type=\"checkbox\" />\r\n      <label class=\"checkbox\" for=\"apples\">\r\n        <span>\r\n          <svg width=\"12px\" height=\"10px\">\r\n            <use xlink:href=\"#check\"></use>\r\n          </svg>\r\n        </span>\r\n        <span>Apples</span>\r\n      </label>\r\n      <input class=\"checkbox-input\" id=\"oranges\" type=\"checkbox\" />\r\n      <label class=\"checkbox\" for=\"oranges\">\r\n        <span>\r\n          <svg width=\"12px\" height=\"10px\">\r\n            <use xlink:href=\"#check\"></use>\r\n          </svg>\r\n        </span>\r\n        <span>Oranges</span>\r\n      </label>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Customization/custom-checkbox"}'), ('"custom-radio-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".radio-container {\n  box-sizing: border-box;\n  background: #ffffff;\n  color: #222;\n  height: 64px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-flow: row wrap;\n}\n\n.radio-container * {\n  box-sizing: border-box;\n}\n\n.radio-input {\n  appearance: none;\n  background-color: #ffffff;\n  width: 16px;\n  height: 16px;\n  border: 1px solid #cccfdb;\n  margin: 0;\n  border-radius: 50%;\n  display: grid;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.3s ease;\n}\n\n.radio-input::before {\n  content: \"\";\n  width: 6px;\n  height: 6px;\n  border-radius: 50%;\n  transform: scale(0);\n  transition: 0.3s transform ease-in-out;\n  box-shadow: inset 6px 6px #ffffff;\n}\n\n.radio-input:checked {\n  background: #0077ff;\n  border-color: #0077ff;\n}\n\n.radio-input:checked::before {\n  transform: scale(1);\n}\n\n.radio {\n  cursor: pointer;\n  padding: 6px 8px;\n}\n\n.radio:not(:last-child) {\n  margin-right: 6px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Custom radio button\r\n    </h1>\r\n    <div class=\"radio-container\">\r\n      <input class=\"radio-input\" id=\"apples\" type=\"radio\" name=\"fruit\" />\r\n      <label class=\"radio\" for=\"apples\">Apples</label>\r\n      <input class=\"radio-input\" id=\"oranges\" type=\"radio\" name=\"fruit\" />\r\n      <label class=\"radio\" for=\"oranges\">Oranges</label>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Customization/custom-radio-button"}'), ('"custom-scrollbar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".custom-scrollbar {\n  height: 70px;\n  overflow-y: scroll;\n}\n\n.custom-scrollbar::-webkit-scrollbar {\n  width: 8px;\n}\n\n.custom-scrollbar::-webkit-scrollbar-track {\n  background: #1E3F20;\n  border-radius: 12px;\n}\n\n.custom-scrollbar::-webkit-scrollbar-thumb {\n  background: #4A7856;\n  border-radius: 12px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Custom scrollbar\r\n    </h1>\r\n    <div class=\"custom-scrollbar\">\r\n      <p>\r\n        Lorem ipsum dolor sit amet consectetur adipisicing elit.<br />\r\n        Iure id exercitationem nulla qui repellat laborum vitae, <br />\r\n        molestias tempora velit natus. Quas, assumenda nisi. <br />\r\n        Quisquam enim qui iure, consequatur velit sit?\r\n      </p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Customization/custom-scrollbar"}'), ('"custom-text-selection"', '"Prsnt"', '"vanilla"', '{"demo.css": "::selection {\n  background: aquamarine;\n  color: black;\n}\n\n.custom-text-selection::selection {\n  background: deeppink;\n  color: white;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Custom text selection\r\n    </h1>\r\n    <p class=\"custom-text-selection\">Select some of this text.</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Customization/custom-text-selection"}'), ('"responsive-favicon-dark-mode"', '"Prsnt"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n    <!-- Provided you have a rendered PNG fallback named favicon.png -->\r\n    <link rel=\"icon\" type=\"image/png\" href=\"favicon.png\" />\r\n    <!-- Provided the SVG icon is named favicon.svg -->\r\n    <link rel=\"icon\" type=\"image/svg\" href=\"favicon.svg\" />\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      How can I create a custom responsive favicon for dark mode?\r\n    </h1>\r\n    <svg\r\n      xmlns=\"http://www.w3.org/2000/svg\"\r\n      width=\"24\"\r\n      height=\"24\"\r\n      viewBox=\"0 0 24 24\"\r\n    >\r\n      <style>\r\n        #icon {\r\n          stroke: #000;\r\n          stroke-width: 2px;\r\n          stroke-linecap: round;\r\n          stroke-linejoin: round;\r\n          fill: none;\r\n        }\r\n\r\n        @media (prefers-color-scheme: dark) {\r\n          #icon {\r\n            stroke: #fff;\r\n          }\r\n        }\r\n      </style>\r\n      <g id=\"icon\">\r\n        <path d=\"M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z\"></path>\r\n        <line x1=\"3\" y1=\"6\" x2=\"21\" y2=\"6\"></line>\r\n        <path d=\"M16 10a4 4 0 0 1-8 0\"></path>\r\n      </g>\r\n    </svg>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Customization/responsive-favicon-dark-mode"}'), ('"accordion"', '"Prsnt"', '"vanilla"', '{"demo.css": ".accordion {\r\n    /* Border */\r\n    border: 1px solid #d1d5db;\r\n    border-bottom-color: transparent;\r\n    border-radius: 4px;\r\n}\r\n\r\n.accordion__item {\r\n    border-bottom: 1px solid #d1d5db;\r\n}\r\n\r\n.accordion__header {\r\n    /* Center the content horizontally */\r\n    align-items: center;\r\n    display: flex;\r\n\r\n    cursor: pointer;\r\n    padding: 16px;\r\n}\r\n\r\n.accordion__toggle {\r\n    margin-right: 12px;\r\n}\r\n\r\n.accordion__title {\r\n    /* Take remaining width */\r\n    flex: 1;\r\n}\r\n\r\n.accordion__content {\r\n    border-top: 1px solid #d1d5db;\r\n    padding: 16px;\r\n}\r\n\r\n.accordion__item--collapsed .accordion__content {\r\n    display: none;\r\n}\r\n.accordion__item--expanded .accordion__content {\r\n    display: block;\r\n}", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Accordion\r\n    </h1>\r\n    <!-- Container -->\r\n    <div class=\"accordion\">\r\n      <!-- Collapsed item -->\r\n      <div class=\"accordion__item accordion__item--collapsed\">\r\n        <!-- Heading -->\r\n        <div class=\"accordion__header\">\r\n          <!-- The toggle icon -->\r\n          <div class=\"accordion__toggle\">Toggle Icon</div>\r\n\r\n          <!-- The title -->\r\n          <div class=\"accordion__title\">Title</div>\r\n        </div>\r\n\r\n        <!-- The content -->\r\n        <div class=\"accordion__content\">Content</div>\r\n      </div>\r\n\r\n      <!-- Expanded item -->\r\n      <div class=\"accordion__item accordion__item--expanded\">Expanded</div>\r\n\r\n      <!-- Repeat other item -->\r\n      Repeat Other Item\r\n    </div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/accordion"}'), ('"arrow-buttons"', '"Prsnt"', '"vanilla"', '{"demo.css": ".arrow-button {\n  /* Transparent background */\n  background-color: transparent;\n\n  /* Size */\n  height: 12px;\n  width: 12px;\n}\n\n.arrow-button--t {\n  /* Edges */\n  border-left: 1px solid #d1d5db;\n  border-top: 1px solid #d1d5db;\n  transform: translateY(25%) rotate(45deg);\n}\n\n.arrow-button--r {\n  /* Edges */\n  border-right: 1px solid #d1d5db;\n  border-top: 1px solid #d1d5db;\n  transform: translateX(-25%) rotate(45deg);\n}\n\n.arrow-button--b {\n  /* Edges */\n  border-bottom: 1px solid #d1d5db;\n  border-right: 1px solid #d1d5db;\n  transform: translateY(-25%) rotate(45deg);\n}\n\n.arrow-button--l {\n  /* Edges */\n  border-bottom: 1px solid #d1d5db;\n  border-left: 1px solid #d1d5db;\n  transform: translateX(25%) rotate(45deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Arrow Buttons\r\n    </h1>\r\n    <!-- Up arrow button -->\r\n    <button class=\"arrow-buttons\">\r\n      <!-- Arrow -->\r\n      <div class=\"arrow-button arrow-button--t\"></div>\r\n\r\n      <!-- Content -->\r\n      ...\r\n    </button>\r\n\r\n    <!-- Right arrow button -->\r\n    <button class=\"arrow-buttons\">\r\n      <!-- Content -->\r\n      ...\r\n\r\n      <!-- Arrow -->\r\n      <div class=\"arrow-button arrow-button--r\"></div>\r\n    </button>\r\n\r\n    <!-- Down arrow button -->\r\n    <button class=\"arrow-buttons\">\r\n      <!-- Arrow -->\r\n      <div class=\"arrow-button arrow-button--b\"></div>\r\n\r\n      <!-- Content -->\r\n      ...\r\n    </button>\r\n\r\n    <!-- Left arrow button -->\r\n    <button class=\"arrow-buttons\">\r\n      <!-- Arrow -->\r\n      <div class=\"arrow-button arrow-button--l\"></div>\r\n\r\n      <!-- Content -->\r\n      ...\r\n    </button>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/arrow-buttons"}'), ('"avatar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".avatar {\n  /* Rounded border */\n  border-radius: 50%;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Size */\n  height: 4rem;\n  width: 4rem;\n}\n\n.avatar__image {\n  /* Size */\n  height: 50%;\n  width: 50%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Avatar\r\n    </h1>\r\n    <div class=\"avatar\">\r\n      <!-- Avatar image -->\r\n      <img class=\"avatar__image\" src=\"...\" />\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/avatar"}'), ('"avatar-list"', '"Prsnt"', '"vanilla"', '{"demo.css": ".avatars {\n  display: flex;\n}\n\n.avatars__item {\n  /* Nagative margin make avatar overlap to previous one */\n  margin-left: -0.25rem;\n}\n\n.avatars__image {\n  /* Add a white curve between avatars */\n  box-shadow: 0 0 0 0.25rem #fff;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Rounded border */\n  border-radius: 9999px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Avatar List\r\n    </h1>\r\n    <div class=\"avatars\">\r\n      <!-- Avatar item -->\r\n      <div class=\"avatars__item\">\r\n        <div class=\"avatars__image\">\r\n          <!-- Image -->\r\n          Image\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Repeat other avatars -->\r\n      Repeat Other Avatars\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/avatar-list"}'), ('"badge"', '"Prsnt"', '"vanilla"', '{"demo.css": ".badge {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Colors */\n  background-color: #d1d5db;\n  color: #fff;\n\n  /* Rounded border */\n  border-radius: 9999px;\n  height: 3rem;\n  width: 3rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Badge\r\n    </h1>\r\n    <div class=\"badge\">...</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/badge"}'), ('"calendar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".calendar {\n  display: grid;\n  grid-template-columns: repeat(7, 1fr);\n}\n\n.calendar__weekday {\n  border-bottom: 1px solid #d1d5db;\n  padding: 0.125rem;\n}\n\n.calendar__day {\n  border-bottom: 1px solid #d1d5db;\n  border-right: 1px solid #d1d5db;\n  padding: 0.25rem;\n  text-align: center;\n}\n\n.calendar__day--current {\n  background-color: #3b82f6;\n  color: #fff;\n}\n\n.calendar__day:nth-child(7n + 1) {\n  border-left: 1px solid #d1d5db;\n}\n\n.calendar__day--disabled {\n  color: #d1d5db;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Calendar\r\n    </h1>\r\n    <div class=\"calendar\">\r\n      <!-- Week days -->\r\n      <div class=\"calendar__weekday\">Mon</div>\r\n      <div class=\"calendar__weekday\">Tue</div>\r\n      <div class=\"calendar__weekday\">Wed</div>\r\n      <div class=\"calendar__weekday\">Thu</div>\r\n      <div class=\"calendar__weekday\">Fri</div>\r\n      <div class=\"calendar__weekday\">Sat</div>\r\n      <div class=\"calendar__weekday\">Sun</div>\r\n\r\n      <!-- Days of the previous month -->\r\n      <div class=\"calendar__day calendar__day--disabled\">30</div>\r\n      <div class=\"calendar__day calendar__day--disabled\">31</div>\r\n\r\n      <!-- Days of the current month -->\r\n      <div class=\"calendar__day\">1</div>\r\n      <div class=\"calendar__day\">2</div>\r\n\r\n      <!-- The current day -->\r\n      <div class=\"calendar__day calendar__day--current\">...</div>\r\n\r\n      <!-- Days of the next month -->\r\n      <div class=\"calendar__day calendar__day--disabled\">1